def set_data_path(data_dir: str, hardware: bool = False, training: bool = True, graph_type: str = "default") -> str:    
    if hardware:
        if graph_type == "erdos_renyi":
            final_path_hardware = f"{data_dir}/hardware/{graph_type}"
        elif graph_type == "heavy_hex":
            final_path_hardware = f"{data_dir}/hardware/{graph_type}"
        elif graph_type == "line_to_full":
            final_path_hardware = f"{data_dir}/hardware/{graph_type}"
        elif graph_type == "random_regular":
            final_path_hardware = f"{data_dir}/hardware/{graph_type}" 
        else:
            final_path_hardware = ""

    if training:
        if graph_type == "erdos_renyi":
            final_path_training = f"{data_dir}/training/{graph_type}"
        elif graph_type == "heavy_hex":
            final_path_training = f"{data_dir}/training/{graph_type}"
        elif graph_type == "line_to_full":
            final_path_training = f"{data_dir}/training/{graph_type}"
        elif graph_type == "random_regular":
            final_path_training = f"{data_dir}/training/{graph_type}" 
        else:
            final_path_training = ""

    if hardware and training:
        return final_path_hardware, final_path_training
    if training:
        return final_path_training
    else:
        return final_path_hardware

def load_problem_instance(problem_path: str, graph_type: str) -> str:
    if graph_type == "erdos_renyi" :
        final_instance_path = f"{problem_path}/{graph_type}"
    elif graph_type == "heavy_hex":
        final_instance_path = f"{problem_path}/{graph_type}"
    elif graph_type == "line_to_full":
        final_instance_path = f"{problem_path}/{graph_type}"
    elif graph_type == "random_regular":
        final_instance_path = f"{problem_path}/{graph_type}"
    
    return final_instance_path

class QAOAHardware:

    def __init__(self, short_name, total_time, num_shots, 
                problem_class, method, eval_energy, result_file):  # Each isntance of class holds uniue data
        self.instance_name = short_name
        self.QPU_time = total_time
        self.num_shots = num_shots
        self.problem_class = problem_class
        self.training_method = method
        self.expected_energy = eval_energy
        self.result_file = result_file

    # Method to return problem instance file paths for hardware
    @classmethod
    def locate_hardware_instance(cls, final_path_hardware: str, graph_type: str, instance: str, num_nodes: str, p: str,
        ER_probability: str = None, swap_layers: str = None, degree: str = None) -> list[Path]:
        
        if graph_type == "heavy_hex":
            instance_path = f"00{instance}N{num_nodes}HH*_{p}_*.json"
        elif graph_type == "erdos_renyi":
            instance_path = f"00{instance}N{num_nodes}ER{ER_probability}_{p}_*.json"
        elif graph_type == "line_to_full":
            instance_path = f"00{instance}N{num_nodes}L2S{swap_layers}_{p}_*.json"
        elif graph_type == "random_regular":
            instance_path = f"00{instance}N{num_nodes}R{degree}R*_{p}_*.json"
        else:
            return []

        instance_paths_final_hardware = list(Path(final_path_hardware).glob(instance_path))
        
        return instance_paths_final_hardware

    # Method to load problem instance file paths for hardware and return class instances
    @classmethod
    def load_hardware_instance(cls, instance_path: Path) -> list["QAOAHardware"]:

        all_data: list["QAOAHardware"] = []

        with instance_path.open("r") as f:
            content = json.load(f)

        # Convert to list if not already
        if not isinstance(content, list):
            content = [content]

        for data in content:
            
            # Job-level fields
            QPU_time = data.get("total_time")
            num_shots = data.get("num_shots")

            # Check that this is a circuit-level record 
            metadata = data.get("metadata")
            if not metadata:
                continue

            circuit_md = metadata.get("circuit_metadata")
            if not circuit_md:
                continue

            # Require eval_energy (defines a valid QAOA run) 
            if "eval_energy" not in circuit_md:
                continue

            # Required circuit-level fields ----
            instance_name = circuit_md.get("short_name")
            problem_class = circuit_md.get("problem_class")
            training_method = circuit_md.get("method")
            expected_energy = circuit_md.get("eval_energy")
            result_file = circuit_md.get("result_file")

            # If any essential circuit info is missing, skip
            if any(v is None for v in (
                instance_name,
                problem_class,
                training_method,
                expected_energy,
            )):
                continue

            run = cls(
                instance_name,
                QPU_time,
                num_shots,
                problem_class,
                training_method,
                expected_energy,
                result_file,
            )

            all_data.append(run)

        return all_data

class QAOATraining:

    def __init__(
        self,
        save_file,
        duration,
        pre_processor_name,
        train_duration_iter,
        energy_iter,
        trainer_name_iter,
        train_duration_layer,
        energy_layer,
        trainer_name_layer,
        num_depth_iter,
    ):
        self.instance_name = save_file
        self.pre_processing_time = duration
        self.pre_processor_name = pre_processor_name

        self.train_duration_per_iter = train_duration_iter
        self.expected_energy_per_iter = energy_iter
        self.trainer_name_per_iter = trainer_name_iter

        self.train_duration_per_layer = train_duration_layer
        self.expected_energy_per_layer = energy_layer
        self.trainer_name_per_layer = trainer_name_layer

        self.num_depth_iter = num_depth_iter

    @classmethod
    def locate_training_instance(cls, final_path_training: str, graph_type: str, instance: str, num_nodes: str, p: str,
                                 trainer: str, Evaluator: str, opt: bool = False, ER_probability: str = None,
                                 swap_layers: str = None, degree: str = None, bond_dimension: str = None,
                                 max_weight: str = None) -> list[Path]:

        if graph_type == "heavy_hex":
            if opt:
                if Evaluator == "MPS":
                    instance_path = f"*00{instance}N{num_nodes}HH*_MC_{trainer}_{Evaluator}_optBD{bond_dimension}_{p}.json"
                elif Evaluator == "PP":
                    instance_path = f"*00{instance}N{num_nodes}HH*_MC_{trainer}_{Evaluator}_optMW{max_weight}_{p}.json"
                else:
                    instance_path = f"*00{instance}N{num_nodes}HH*_MC_{trainer}_SV_{p}.json"
            else:
                if Evaluator == "MPS":
                    instance_path = f"*00{instance}N{num_nodes}HH*_MC_{trainer}_{Evaluator}_noOptBD{bond_dimension}_{p}.json"
                elif Evaluator == "PP":
                    instance_path = f"*00{instance}N{num_nodes}HH*_MC_{trainer}_{Evaluator}_noOptMW{max_weight}_{p}.json"
                else:
                    instance_path = f"*00{instance}N{num_nodes}HH*_MC_{trainer}_SV_noOpt_{p}.json"

        elif graph_type == "erdos_renyi":
            if opt:
                if Evaluator == "MPS":
                    instance_path = f"*00{instance}N{num_nodes}ER{ER_probability}_MC_{trainer}_{Evaluator}_optBD{bond_dimension}_{p}.json"
                elif Evaluator == "PP":
                    instance_path = f"*00{instance}N{num_nodes}ER{ER_probability}_MC_{trainer}_{Evaluator}_optMW{max_weight}_{p}.json"
                else:
                    instance_path = f"*00{instance}N{num_nodes}ER{ER_probability}_MC_{trainer}_SV_{p}.json"
            else:
                if Evaluator == "MPS":
                    instance_path = f"*00{instance}N{num_nodes}ER{ER_probability}_MC_{trainer}_{Evaluator}_noOptBD{bond_dimension}_{p}.json"
                elif Evaluator == "PP":
                    instance_path = f"*00{instance}N{num_nodes}ER{ER_probability}_MC_{trainer}_{Evaluator}_noOptMW{max_weight}_{p}.json"
                else:
                    instance_path = f"*00{instance}N{num_nodes}ER{ER_probability}_MC_{trainer}_SV_noOpt_{p}.json"

        elif graph_type == "line_to_full":
            if opt:
                if Evaluator == "MPS":
                    instance_path = f"*00{instance}N{num_nodes}L2S{swap_layers}_MC_{trainer}_{Evaluator}_optBD{bond_dimension}_{p}.json"
                elif Evaluator == "PP":
                    instance_path = f"*00{instance}N{num_nodes}L2S{swap_layers}_MC_{trainer}_{Evaluator}_optMW{max_weight}_{p}.json"
                else:
                    instance_path = f"*00{instance}N{num_nodes}L2S{swap_layers}_MC_{trainer}_SV_{p}.json"
            else:
                if Evaluator == "MPS":
                    instance_path = f"*00{instance}N{num_nodes}L2S{swap_layers}_MC_{trainer}_{Evaluator}_noOptBD{bond_dimension}_{p}.json"
                elif Evaluator == "PP":
                    instance_path = f"*00{instance}N{num_nodes}L2S{swap_layers}_MC_{trainer}_{Evaluator}_noOptMW{max_weight}_{p}.json"
                else:
                    instance_path = f"*00{instance}N{num_nodes}L2S{swap_layers}_MC_{trainer}_SV_noOpt_{p}.json"

        elif graph_type == "random_regular":
            if opt:
                if Evaluator == "MPS":
                    instance_path = f"*00{instance}N{num_nodes}R{degree}R_MC_{trainer}_{Evaluator}_optBD{bond_dimension}_{p}.json"
                elif Evaluator == "PP":
                    instance_path = f"*00{instance}N{num_nodes}R{degree}R_MC_{trainer}_{Evaluator}_optMW{max_weight}_{p}.json"
                else:
                    instance_path = f"*00{instance}N{num_nodes}R{degree}R_MC_{trainer}_SV_{p}.json"
            else:
                if Evaluator == "MPS":
                    instance_path = f"*00{instance}N{num_nodes}R{degree}R_MC_{trainer}_{Evaluator}_noOptBD{bond_dimension}_{p}.json"
                elif Evaluator == "PP":
                    instance_path = f"*00{instance}N{num_nodes}R{degree}R_MC_{trainer}_{Evaluator}_noOptMW{max_weight}_{p}.json"
                else:
                    instance_path = f"*00{instance}N{num_nodes}R{degree}R_MC_{trainer}_SV_noOpt_{p}.json"
        else:
            return []

        return list(Path(final_path_training).glob(instance_path))

    @classmethod
    def load_training_instance(cls, instance_path: Path) -> "QAOATraining":

        with instance_path.open("r") as f:
            data = json.load(f)

        args = data.get("args")
        if args is None or "save_file" not in args:
            return None
        instance_name = args["save_file"]

        pre_processing = data.get("pre_processing")
        if pre_processing is None:
            return None
        if "pre_processor_name" not in pre_processing or "duration" not in pre_processing:
            return None

        pre_processor_name = pre_processing["pre_processor_name"]
        pre_processing_time = pre_processing["duration"]

        num_iterations = []
        for key in data.keys():
            try:
                int(key)
                num_iterations.append(key)
            except ValueError:
                pass
        num_iterations = sorted(num_iterations, key=int)

        train_duration_per_iter = []
        expected_energy_per_iter = []
        trainer_name_per_iter = []

        train_duration_per_layer = []
        expected_energy_per_layer = []
        trainer_name_per_layer = []

        num_depth_iter = []

        for element in num_iterations:
            classical_iteration = data.get(element)
            if classical_iteration is None:
                continue

            if "train_duration" not in classical_iteration or "energy" not in classical_iteration:
                continue
            if "trainer" not in classical_iteration:
                continue

            train_duration_per_iter.append(classical_iteration["train_duration"])
            expected_energy_per_iter.append(classical_iteration["energy"])
            trainer_name_per_iter.append(classical_iteration["trainer"])

            current_iter_depth_keys = []
            current_iter_durations = []
            current_iter_energies = []
            current_iter_trainers = []

            for key2 in classical_iteration.keys():
                try:
                    int(key2)
                    current_iter_depth_keys.append(key2)
                except ValueError:
                    pass
            current_iter_depth_keys = sorted(current_iter_depth_keys, key=int)

            for element2 in current_iter_depth_keys:
                layer_iteration = classical_iteration.get(element2)
                if layer_iteration is None:
                    continue

                if "train_duration" not in layer_iteration or "energy" not in layer_iteration:
                    continue
                if "trainer" not in layer_iteration:
                    continue

                current_iter_durations.append(layer_iteration["train_duration"])
                current_iter_energies.append(layer_iteration["energy"])
                current_iter_trainers.append(layer_iteration["trainer"])

            num_depth_iter.append(current_iter_depth_keys)
            train_duration_per_layer.append(current_iter_durations)
            expected_energy_per_layer.append(current_iter_energies)
            trainer_name_per_layer.append(current_iter_trainers)

        return cls(
            instance_name,
            pre_processing_time,
            pre_processor_name,
            train_duration_per_iter,
            expected_energy_per_iter,
            trainer_name_per_iter,
            train_duration_per_layer,
            expected_energy_per_layer,
            trainer_name_per_layer,
            num_depth_iter,
        )









